# VPC and CIDR plan (non-overlapping; this VPC owns 10.20.0.0/16)
resource "aws_vpc" "main" {
  cidr_block           = "10.20.0.0/16"
  enable_dns_support   = true   # Amazon resolver
  enable_dns_hostnames = true   # required for private DNS / interface endpoints
}

# --- Subnets: small public, large private, one pair per AZ ---
# AZ a
resource "aws_subnet" "public_a"  { vpc_id = aws_vpc.main.id  cidr_block = "10.20.0.0/24"   availability_zone = "eu-west-1a"  map_public_ip_on_launch = true }
resource "aws_subnet" "private_a" { vpc_id = aws_vpc.main.id  cidr_block = "10.20.16.0/20"  availability_zone = "eu-west-1a" }
# AZ b
resource "aws_subnet" "public_b"  { vpc_id = aws_vpc.main.id  cidr_block = "10.20.1.0/24"   availability_zone = "eu-west-1b"  map_public_ip_on_launch = true }
resource "aws_subnet" "private_b" { vpc_id = aws_vpc.main.id  cidr_block = "10.20.32.0/20"  availability_zone = "eu-west-1b" }

resource "aws_internet_gateway" "igw" { vpc_id = aws_vpc.main.id }

# One NAT Gateway PER AZ (HA + no cross-AZ NAT charges).
resource "aws_eip" "nat_a" { domain = "vpc" }
resource "aws_eip" "nat_b" { domain = "vpc" }
resource "aws_nat_gateway" "a" { allocation_id = aws_eip.nat_a.id  subnet_id = aws_subnet.public_a.id }
resource "aws_nat_gateway" "b" { allocation_id = aws_eip.nat_b.id  subnet_id = aws_subnet.public_b.id }

# Public route table: 0.0.0.0/0 -> IGW (shared by both public subnets).
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route { cidr_block = "0.0.0.0/0"  gateway_id = aws_internet_gateway.igw.id }
}
resource "aws_route_table_association" "pub_a" { subnet_id = aws_subnet.public_a.id  route_table_id = aws_route_table.public.id }
resource "aws_route_table_association" "pub_b" { subnet_id = aws_subnet.public_b.id  route_table_id = aws_route_table.public.id }

# Private route tables: each AZ -> its OWN NAT (no cross-AZ).
resource "aws_route_table" "private_a" {
  vpc_id = aws_vpc.main.id
  route { cidr_block = "0.0.0.0/0"  nat_gateway_id = aws_nat_gateway.a.id }
}
resource "aws_route_table" "private_b" {
  vpc_id = aws_vpc.main.id
  route { cidr_block = "0.0.0.0/0"  nat_gateway_id = aws_nat_gateway.b.id }
}
resource "aws_route_table_association" "priv_a" { subnet_id = aws_subnet.private_a.id  route_table_id = aws_route_table.private_a.id }
resource "aws_route_table_association" "priv_b" { subnet_id = aws_subnet.private_b.id  route_table_id = aws_route_table.private_b.id }

# --- Security groups: reference each other, never hardcode IPs between tiers ---
resource "aws_security_group" "alb" { name = "alb-sg"  vpc_id = aws_vpc.main.id }
resource "aws_security_group" "app" { name = "app-sg"  vpc_id = aws_vpc.main.id }
resource "aws_security_group" "db"  { name = "db-sg"   vpc_id = aws_vpc.main.id }

# ALB: the ONLY place 0.0.0.0/0 ingress is allowed (HTTPS from the internet).
resource "aws_security_group_rule" "alb_in_https" {
  type = "ingress" security_group_id = aws_security_group.alb.id
  protocol = "tcp" from_port = 443 to_port = 443 cidr_blocks = ["0.0.0.0/0"]
}
# App accepts traffic ONLY from the ALB SG (stateful: return is automatic).
resource "aws_security_group_rule" "app_in_from_alb" {
  type = "ingress" security_group_id = aws_security_group.app.id
  protocol = "tcp" from_port = 443 to_port = 443 source_security_group_id = aws_security_group.alb.id
}
# DB accepts Postgres ONLY from the App SG.
resource "aws_security_group_rule" "db_in_from_app" {
  type = "ingress" security_group_id = aws_security_group.db.id
  protocol = "tcp" from_port = 5432 to_port = 5432 source_security_group_id = aws_security_group.app.id
}
